import bcrypt from 'bcryptjs';
import { Address } from './dto/address.struct'
import { Shipment } from './entities/shipment.entity'
import { ShippingCarrier } from './enums/shipping-carrier.enum'
import { addDays } from 'date-fns';
import { format } from 'date-fns';

export function selectCarrier(destination: Address, weight: number): ShippingCarrier {
  if ((destination.country !== 'US')) {
    return ShippingCarrier.FedEx;
  }
  if ((weight > 70)) {
    return ShippingCarrier.Ups;
  }
  return ShippingCarrier.Usps;
}

export function calculateEstimatedDelivery(carrier: ShippingCarrier, destination: Address): Date {
  const days: number = getEstimatedDays(carrier, destination);
  return addDays(new Date(), days);
}

export function getEstimatedDays(carrier: ShippingCarrier, destination: Address): number {
  const isInternational: boolean = (destination.country !== 'US');
  if (isInternational) {
    return ((carrier === ShippingCarrier.FedEx) ? 5 : 7);
  }
  if ((carrier === ShippingCarrier.Usps)) {
    return 5;
  }
  if ((carrier === ShippingCarrier.Ups)) {
    return 3;
  }
  if ((carrier === ShippingCarrier.FedEx)) {
    return 3;
  }
  return 5;
}

